type RegexLike = {
    exec(s: string): RegExpExecArray | null;
};
type Handler<T> = (m: RegExpExecArray, ...groups: string[]) => T;
type Pair<T> = [RegexLike, Handler<T>];
type Fallback<T> = T | ((s: string) => T);
type FlattenPairs<P extends readonly Pair<any>[]> = P extends [infer H, ...infer R] ? H extends [infer A, infer B] ? [A, B, ...FlattenPairs<R extends Pair<any>[] ? R : []>] : [] : [];
export declare function match<T, P extends readonly Pair<T>[]>(...args: [...FlattenPairs<P>, Fallback<T>?]): (s: string) => T | undefined;
export declare function match<T, P extends readonly Pair<T>[]>(s: string, ...args: [...FlattenPairs<P>, Fallback<T>?]): T | undefined;
